/*
 * Main Computer local HyperFormula-compatible browser build.
 *
 * This same-origin file is intentionally small so local/offline spreadsheet
 * smoke tests and basic workbook formulas can run before the CDN fallback is
 * needed. It implements the subset of the HyperFormula browser API used by
 * the Main Computer spreadsheet app:
 *
 *   HyperFormula.buildFromSheets(sheets, options)
 *   HyperFormula.getRegisteredFunctionNames()
 *   hf.getSheetId(sheetName)
 *   hf.getCellValue({sheet, row, col})
 *   hf.destroy()
 *
 * Smoke target: =A1+B1.
 * It is not a full upstream HyperFormula distribution. Keep the CDN fallback
 * in the loader for complete upstream formula compatibility.
 */
(function(root){
  "use strict";

  const FUNCTION_NAMES = Object.freeze([
    "ABS", "AND", "AVERAGE", "CONCAT", "CONCATENATE", "COUNT", "COUNTA",
    "FALSE", "IF", "INT", "LEFT", "LEN", "LOWER", "MAX", "MID", "MIN",
    "NOT", "OR", "POWER", "ROUND", "ROUNDDOWN", "ROUNDUP", "SQRT",
    "SUM", "TEXTJOIN", "TRIM", "TRUE", "UPPER"
  ]);

  function error(type, message) {
    return {type, message};
  }

  function isError(value) {
    return Boolean(value && typeof value === "object" && (value.type || value.message));
  }

  function columnIndex(name) {
    return String(name || "A").replace(/\$/g, "").toUpperCase().split("").reduce((total, char) => {
      const code = char.charCodeAt(0);
      if (code < 65 || code > 90) return total;
      return total * 26 + code - 64;
    }, 0);
  }

  function cellParts(ref) {
    const match = String(ref || "A1").replace(/\$/g, "").toUpperCase().match(/^([A-Z]+)([1-9][0-9]*)$/);
    if (!match) return null;
    return {col: columnIndex(match[1]), row: Number(match[2])};
  }

  function cellRef(row, col) {
    let name = "";
    let value = Number(col) || 1;
    while (value > 0) {
      const remainder = (value - 1) % 26;
      name = String.fromCharCode(65 + remainder) + name;
      value = Math.floor((value - 1) / 26);
    }
    return `${name || "A"}${Number(row) || 1}`;
  }

  function toNumber(value) {
    if (isError(value)) return value;
    if (Array.isArray(value)) return toNumber(value.flat(Infinity)[0] ?? 0);
    if (value === true) return 1;
    if (value === false || value == null || value === "") return 0;
    const numeric = Number(value);
    return Number.isFinite(numeric) ? numeric : error("VALUE", "#VALUE!");
  }

  function toText(value) {
    if (isError(value)) return value;
    if (Array.isArray(value)) return value.flat(Infinity).map(toText).join("");
    if (value == null) return "";
    return String(value);
  }

  function truthy(value) {
    if (isError(value)) return value;
    if (Array.isArray(value)) return value.flat(Infinity).some((item) => truthy(item) === true);
    if (typeof value === "string") return value.length > 0 && value !== "0" && value.toLowerCase() !== "false";
    return Boolean(value);
  }

  function flatten(values) {
    const result = [];
    values.forEach((value) => {
      if (Array.isArray(value)) result.push(...flatten(value));
      else result.push(value);
    });
    return result;
  }

  function tokenize(expression) {
    const tokens = [];
    let index = 0;
    while (index < expression.length) {
      const char = expression[index];
      if (/\s/.test(char)) {
        index += 1;
        continue;
      }
      if (char === '"' || char === "'") {
        const quote = char;
        let value = "";
        index += 1;
        while (index < expression.length) {
          const current = expression[index];
          if (current === quote) {
            if (expression[index + 1] === quote) {
              value += quote;
              index += 2;
              continue;
            }
            index += 1;
            break;
          }
          value += current;
          index += 1;
        }
        tokens.push({type: "string", value});
        continue;
      }
      const two = expression.slice(index, index + 2);
      if (["<=", ">=", "<>", "=="].includes(two)) {
        tokens.push({type: "op", value: two});
        index += 2;
        continue;
      }
      if ("+-*/^&=<>(),:!".includes(char)) {
        tokens.push({type: "op", value: char});
        index += 1;
        continue;
      }
      if (/[0-9.]/.test(char)) {
        const match = expression.slice(index).match(/^(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][+-]?\d+)?/);
        if (match) {
          tokens.push({type: "number", value: Number(match[0])});
          index += match[0].length;
          continue;
        }
      }
      const match = expression.slice(index).match(/^[A-Za-z_$][A-Za-z0-9_.$]*/);
      if (match) {
        tokens.push({type: "identifier", value: match[0]});
        index += match[0].length;
        continue;
      }
      tokens.push({type: "op", value: char});
      index += 1;
    }
    tokens.push({type: "eof", value: ""});
    return tokens;
  }

  class Parser {
    constructor(engine, sheetName, expression, visited) {
      this.engine = engine;
      this.sheetName = sheetName;
      this.tokens = tokenize(expression);
      this.index = 0;
      this.visited = visited;
    }

    peek(value) {
      const token = this.tokens[this.index] || {type: "eof", value: ""};
      return value == null ? token : token.value === value;
    }

    consume(value = null) {
      const token = this.tokens[this.index] || {type: "eof", value: ""};
      if (value != null && token.value !== value) return null;
      this.index += 1;
      return token;
    }

    parse() {
      const value = this.parseComparison();
      if (isError(value)) return value;
      if (!this.peek()) return value;
      return value;
    }

    parseComparison() {
      let left = this.parseConcat();
      while (["=", "==", "<>", "<", ">", "<=", ">="].includes(this.peek().value)) {
        const op = this.consume().value;
        const right = this.parseConcat();
        if (isError(left)) return left;
        if (isError(right)) return right;
        const a = Array.isArray(left) ? flatten([left])[0] : left;
        const b = Array.isArray(right) ? flatten([right])[0] : right;
        if (op === "=" || op === "==") left = a == b; // eslint-disable-line eqeqeq
        else if (op === "<>") left = a != b; // eslint-disable-line eqeqeq
        else if (op === "<") left = a < b;
        else if (op === ">") left = a > b;
        else if (op === "<=") left = a <= b;
        else if (op === ">=") left = a >= b;
      }
      return left;
    }

    parseConcat() {
      let left = this.parseAdditive();
      while (this.peek("&")) {
        this.consume("&");
        const right = this.parseAdditive();
        if (isError(left)) return left;
        if (isError(right)) return right;
        const leftText = toText(left);
        const rightText = toText(right);
        if (isError(leftText)) return leftText;
        if (isError(rightText)) return rightText;
        left = String(leftText) + String(rightText);
      }
      return left;
    }

    parseAdditive() {
      let left = this.parseMultiplicative();
      while (this.peek("+") || this.peek("-")) {
        const op = this.consume().value;
        const right = this.parseMultiplicative();
        const a = toNumber(left);
        const b = toNumber(right);
        if (isError(a)) return a;
        if (isError(b)) return b;
        left = op === "+" ? a + b : a - b;
      }
      return left;
    }

    parseMultiplicative() {
      let left = this.parsePower();
      while (this.peek("*") || this.peek("/")) {
        const op = this.consume().value;
        const right = this.parsePower();
        const a = toNumber(left);
        const b = toNumber(right);
        if (isError(a)) return a;
        if (isError(b)) return b;
        if (op === "/" && b === 0) return error("DIV_BY_ZERO", "#DIV/0!");
        left = op === "*" ? a * b : a / b;
      }
      return left;
    }

    parsePower() {
      let left = this.parseUnary();
      while (this.peek("^")) {
        this.consume("^");
        const right = this.parseUnary();
        const a = toNumber(left);
        const b = toNumber(right);
        if (isError(a)) return a;
        if (isError(b)) return b;
        left = Math.pow(a, b);
      }
      return left;
    }

    parseUnary() {
      if (this.peek("+")) {
        this.consume("+");
        return this.parseUnary();
      }
      if (this.peek("-")) {
        this.consume("-");
        const value = toNumber(this.parseUnary());
        return isError(value) ? value : -value;
      }
      return this.parsePrimary();
    }

    parsePrimary() {
      const token = this.consume();
      if (!token || token.type === "eof") return "";
      if (token.type === "number") return token.value;
      if (token.type === "string") {
        if (this.peek("!") && /^[A-Za-z_][A-Za-z0-9_ .-]*$/.test(token.value)) {
          this.consume("!");
          const refToken = this.consume();
          return this.parseReferenceOrRange(token.value, refToken);
        }
        return token.value;
      }
      if (token.value === "(") {
        const value = this.parseComparison();
        this.consume(")");
        return value;
      }
      if (token.type === "identifier") {
        if (this.peek("(")) return this.parseFunction(token.value);
        if (this.peek("!")) {
          this.consume("!");
          const refToken = this.consume();
          return this.parseReferenceOrRange(token.value, refToken);
        }
        return this.parseReferenceOrRange(this.sheetName, token);
      }
      return error("VALUE", "#VALUE!");
    }

    parseFunction(name) {
      const fnName = String(name || "").toUpperCase();
      this.consume("(");
      const args = [];
      if (!this.peek(")")) {
        while (!this.peek("eof")) {
          args.push(this.parseComparison());
          if (!this.peek(",")) break;
          this.consume(",");
        }
      }
      this.consume(")");
      return evaluateFunction(fnName, args);
    }

    parseReferenceOrRange(sheetName, refToken) {
      if (!refToken || refToken.type !== "identifier") return error("REF", "#REF!");
      const startRef = refToken.value;
      if (!cellParts(startRef)) {
        const name = String(startRef || "").toUpperCase();
        if (name === "TRUE") return true;
        if (name === "FALSE") return false;
        return error("NAME", "#NAME?");
      }
      if (this.peek(":")) {
        this.consume(":");
        const endToken = this.consume();
        if (!endToken || endToken.type !== "identifier" || !cellParts(endToken.value)) return error("REF", "#REF!");
        return this.engine.rangeValues(sheetName, startRef, endToken.value, this.visited);
      }
      return this.engine.evaluateCell(sheetName, startRef, this.visited);
    }
  }

  function numericArgs(args) {
    const values = flatten(args);
    const result = [];
    for (const value of values) {
      if (isError(value)) return value;
      if (value === "" || value == null || value === false) continue;
      const numeric = Number(value);
      if (Number.isFinite(numeric)) result.push(numeric);
    }
    return result;
  }

  function evaluateFunction(name, args) {
    const firstError = flatten(args).find(isError);
    if (firstError) return firstError;
    switch (name) {
      case "TRUE": return true;
      case "FALSE": return false;
      case "SUM": {
        const numbers = numericArgs(args);
        return isError(numbers) ? numbers : numbers.reduce((total, value) => total + value, 0);
      }
      case "AVERAGE": {
        const numbers = numericArgs(args);
        return isError(numbers) ? numbers : (numbers.length ? numbers.reduce((total, value) => total + value, 0) / numbers.length : 0);
      }
      case "MIN": {
        const numbers = numericArgs(args);
        return isError(numbers) ? numbers : (numbers.length ? Math.min(...numbers) : 0);
      }
      case "MAX": {
        const numbers = numericArgs(args);
        return isError(numbers) ? numbers : (numbers.length ? Math.max(...numbers) : 0);
      }
      case "COUNT": {
        const numbers = numericArgs(args);
        return isError(numbers) ? numbers : numbers.length;
      }
      case "COUNTA":
        return flatten(args).filter((value) => value !== "" && value != null).length;
      case "IF":
        return truthy(args[0]) ? (args.length > 1 ? args[1] : true) : (args.length > 2 ? args[2] : false);
      case "AND":
        return flatten(args).every((value) => truthy(value) === true);
      case "OR":
        return flatten(args).some((value) => truthy(value) === true);
      case "NOT":
        return !truthy(args[0]);
      case "ABS": {
        const value = toNumber(args[0]);
        return isError(value) ? value : Math.abs(value);
      }
      case "INT": {
        const value = toNumber(args[0]);
        return isError(value) ? value : Math.floor(value);
      }
      case "SQRT": {
        const value = toNumber(args[0]);
        return isError(value) ? value : Math.sqrt(value);
      }
      case "POWER": {
        const base = toNumber(args[0]);
        const power = toNumber(args[1]);
        if (isError(base)) return base;
        if (isError(power)) return power;
        return Math.pow(base, power);
      }
      case "ROUND":
      case "ROUNDUP":
      case "ROUNDDOWN": {
        const value = toNumber(args[0]);
        const digits = toNumber(args[1] ?? 0);
        if (isError(value)) return value;
        if (isError(digits)) return digits;
        const factor = Math.pow(10, digits);
        if (name === "ROUNDUP") return (value < 0 ? -1 : 1) * Math.ceil(Math.abs(value) * factor) / factor;
        if (name === "ROUNDDOWN") return (value < 0 ? -1 : 1) * Math.floor(Math.abs(value) * factor) / factor;
        return Math.round(value * factor) / factor;
      }
      case "LEFT": {
        const text = toText(args[0]);
        const count = toNumber(args[1] ?? 1);
        if (isError(text)) return text;
        if (isError(count)) return count;
        return String(text).slice(0, Math.max(0, count));
      }
      case "RIGHT": {
        const text = toText(args[0]);
        const count = toNumber(args[1] ?? 1);
        if (isError(text)) return text;
        if (isError(count)) return count;
        return String(text).slice(Math.max(0, String(text).length - count));
      }
      case "MID": {
        const text = toText(args[0]);
        const start = toNumber(args[1] ?? 1);
        const count = toNumber(args[2] ?? String(text).length);
        if (isError(text)) return text;
        if (isError(start)) return start;
        if (isError(count)) return count;
        return String(text).slice(Math.max(0, start - 1), Math.max(0, start - 1) + Math.max(0, count));
      }
      case "LEN": {
        const text = toText(args[0]);
        return isError(text) ? text : String(text).length;
      }
      case "TRIM": {
        const text = toText(args[0]);
        return isError(text) ? text : String(text).trim().replace(/\s+/g, " ");
      }
      case "LOWER": {
        const text = toText(args[0]);
        return isError(text) ? text : String(text).toLowerCase();
      }
      case "UPPER": {
        const text = toText(args[0]);
        return isError(text) ? text : String(text).toUpperCase();
      }
      case "CONCAT":
      case "CONCATENATE":
        return flatten(args).map(toText).join("");
      case "TEXTJOIN": {
        const delimiter = toText(args[0]);
        const ignoreEmpty = truthy(args[1]);
        if (isError(delimiter)) return delimiter;
        const values = flatten(args.slice(2)).map(toText).filter((value) => !ignoreEmpty || value !== "");
        return values.join(String(delimiter));
      }
      default:
        return error("NAME", "#NAME?");
    }
  }

  class LocalHyperFormula {
    constructor(sheets, options) {
      this.options = options || {};
      this.sheets = {};
      this.sheetNames = [];
      Object.entries(sheets || {}).forEach(([name, matrix]) => {
        const sheetName = String(name || `Sheet${this.sheetNames.length + 1}`);
        this.sheetNames.push(sheetName);
        this.sheets[sheetName] = Array.isArray(matrix) ? matrix : [[]];
      });
      if (!this.sheetNames.length) {
        this.sheetNames.push("Sheet1");
        this.sheets.Sheet1 = [[]];
      }
    }

    static buildFromSheets(sheets, options) {
      return new LocalHyperFormula(sheets, options);
    }

    static getRegisteredFunctionNames() {
      return FUNCTION_NAMES.slice();
    }

    static get version() {
      return "3.2.0-local-main-computer";
    }

    getRegisteredFunctionNames() {
      return LocalHyperFormula.getRegisteredFunctionNames();
    }

    getSheetId(sheetName) {
      const exact = this.sheetNames.find((name) => name === sheetName);
      if (exact) return exact;
      const folded = this.sheetNames.find((name) => name.toLowerCase() === String(sheetName || "").toLowerCase());
      return folded || this.sheetNames[0];
    }

    sheetByName(sheetName) {
      return this.sheets[this.getSheetId(sheetName)] || [[]];
    }

    cellValue(sheetName, ref) {
      const parts = cellParts(ref);
      if (!parts) return "";
      const sheet = this.sheetByName(sheetName);
      const row = sheet[parts.row - 1];
      return row ? row[parts.col - 1] : "";
    }

    rangeValues(sheetName, startRef, endRef, visited) {
      const start = cellParts(startRef);
      const end = cellParts(endRef);
      if (!start || !end) return error("REF", "#REF!");
      const values = [];
      const firstRow = Math.min(start.row, end.row);
      const lastRow = Math.max(start.row, end.row);
      const firstCol = Math.min(start.col, end.col);
      const lastCol = Math.max(start.col, end.col);
      for (let row = firstRow; row <= lastRow; row += 1) {
        const line = [];
        for (let col = firstCol; col <= lastCol; col += 1) {
          line.push(this.evaluateCell(sheetName, cellRef(row, col), visited));
        }
        values.push(line);
      }
      return values;
    }

    evaluateCell(sheetName, ref, visited = new Set()) {
      const sheetId = this.getSheetId(sheetName);
      const key = `${sheetId}!${String(ref || "").toUpperCase()}`;
      if (visited.has(key)) return error("CYCLE", "#CYCLE!");
      const raw = this.cellValue(sheetId, ref);
      if (raw == null) return "";
      if (typeof raw === "number" || typeof raw === "boolean") return raw;
      const text = String(raw);
      if (!text.startsWith("=")) {
        const trimmed = text.trim();
        if (trimmed !== "" && /^[-+]?(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][+-]?\d+)?$/.test(trimmed)) return Number(trimmed);
        return text;
      }
      visited.add(key);
      const parser = new Parser(this, sheetId, text.slice(1), visited);
      const value = parser.parse();
      visited.delete(key);
      return value;
    }

    getCellValue(address) {
      const sheetName = typeof address?.sheet === "number" ? this.sheetNames[address.sheet] : this.getSheetId(address?.sheet);
      const ref = cellRef((Number(address?.row) || 0) + 1, (Number(address?.col) || 0) + 1);
      return this.evaluateCell(sheetName, ref, new Set());
    }

    destroy() {
      this.sheets = {};
      this.sheetNames = [];
    }
  }

  root.HyperFormula = LocalHyperFormula;
  root.HyperFormula.HyperFormula = LocalHyperFormula;
  root.HyperFormula.__MAIN_COMPUTER_LOCAL_COMPAT__ = true;
})(typeof globalThis !== "undefined" ? globalThis : window);
